import { Readable } from 'stream';

/**
 * Processes an initial handshake from a readable stream, waiting for a specific
 * sequence of data ("wait_init" followed by "break"). This function is designed
 * to be testable and avoids blocking the Node.js event loop.
 * @param inputStream The stream to read from (e.g., process.stdin).
 * @param timeoutMs The maximum time to wait for the handshake to complete.
 * @returns A promise that resolves when the handshake is complete or the stream ends.
 */
export async function handleInitialHandshake(
  inputStream: Readable,
  timeoutMs: number = 2000
): Promise<void> {
  return new Promise((resolve, reject) => {
    let buffer = '';

    const timeout = setTimeout(() => {
      cleanup();
      reject(new Error(`Timed out after ${timeoutMs}ms waiting for initial input.`));
    }, timeoutMs);

    const onData = (chunk: Buffer | string) => {
      buffer += chunk.toString();
      // Only proceed if we're in the 'wait_init' state.
      if (buffer.trim().startsWith('wait_init')) {
        // If we receive the 'break' signal, the handshake is complete.
        if (buffer.includes('break')) {
          cleanup();
          resolve();
        }
      } else {
        // If we receive any other data, the handshake phase is over.
        // We unshift the buffer back so other listeners can process it.
        inputStream.unshift(Buffer.from(buffer));
        cleanup();
        resolve();
      }
    };

    const onEnd = () => {
      cleanup();
      resolve(); // Resolve if stream ends, preventing a hang.
    };

    const cleanup = () => {
      clearTimeout(timeout);
      inputStream.removeListener('data', onData);
      inputStream.removeListener('end', onEnd);
    };

    inputStream.on('data', onData);
    inputStream.on('end', onEnd);
  });
}

