import { Readable } from 'stream';

/**
 * Asynchronously waits for initial input from a stream, handling a custom protocol 
 * without blocking the Node.js event loop.
 * It resolves once the stream's buffer no longer strictly equals 'wait_init' or contains 'break'.
 *
 * @param stream The input stream to listen to (e.g., process.stdin).
 * @returns A promise that resolves when the input condition is met.
 */
export function waitForInitialSyncInput(stream: Readable): Promise<void> {
  return new Promise((resolve) => {
    let buffer = '';

    const dataHandler = (chunk: Buffer | string) => {
      buffer += chunk.toString();
      // Check for the exit conditions (not 'wait_init' or includes 'break').
      if (buffer.trim() !== 'wait_init' || buffer.includes('break')) {
        stream.removeListener('data', dataHandler);
        resolve();
      }
      // If the condition is not met, the event loop remains free, waiting for the next 'data' event.
    };

    stream.on('data', dataHandler);
  });
}

